    fun oBPv510GrantUserAccessToViewByIdRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, obPv510RevokeUserAccessToViewByIdRequest: OBPv510RevokeUserAccessToViewByIdRequest) : RequestConfig<OBPv510RevokeUserAccessToViewByIdRequest> {
